function endsWith(value, suffix) {
    return typeof value === "string" && value.length >= suffix.length &&
        value.slice(value.length - suffix.length) === suffix;
}

module.exports = {
    filenameEndsWith: endsWith(__filename, "index.js") ? "index.js" : __filename,
    dirnameEndsWith: endsWith(__dirname, "dirname-pkg") ? "dirname-pkg" : __dirname,
};
